/// @ 1.2.1
// キーワードミュートクエリ — true = 表示
//
// NG ワードを本文か CW に含むノートを隠すテンプレート。
// hit 内の incl の並びを書き換えて自分のミュートリストにする。
// 大文字小文字の揺れを吸収するため比較前に lower で正規化する。
@hit(text) {
	if text == null { return false }
	let lowered = text.lower()
	lowered.incl("懸賞") || lowered.incl("プレゼント企画") || lowered.incl("拡散希望")
}

!hit(note.text) && !hit(note.cw)
